// ─── DUSUN MAP (RW → Dusun) ──────────────────────────────────
export const DUSUN_RW = { 1:["1","2"], 2:["3","6"], 3:["4","5","7"] };

export function getDusun(rw) {
  if (rw === "luar") return 0;
  for (const [d, rws] of Object.entries(DUSUN_RW))
    if (rws.includes(rw)) return +d;
  return 0;
}

export function getDLabel(rw) {
  const d = getDusun(rw);
  return d ? ["","Dusun I","Dusun II","Dusun III"][d] : "Luar Desa";
}

