export const pendingList = [];
export const riwayatList = [];

// ─── STATE ───────────────────────────────────────────────────
export let currentUser = null;

// ─── AUTH ────────────────────────────────────────────────────
export function login(role, username, password) {
  const found = users.find(u => u.username===username && u.password===password && u.role===role);
  if (!found) return null;
  currentUser = found;
  return found;
}
export function logout() { currentUser = null; }

// ─── DATA LOAD (no-op, data sudah inline) ─────────────────────
export async function loadWpData() { /* data sudah ada inline */ }

// ─── STATISTIK ───────────────────────────────────────────────
export function getTotalWP()    { return wpData.length; }
export function getTotalTagihan(){ return wpData.reduce((s,d) => s+d.total, 0); }

export function getStatsByTahun(tahun) {
  const t = String(tahun);
  const hasTunggak = wpData.filter(d => d.tunggakan[t]);
  const total = hasTunggak.reduce((s,d) => s+(d.tunggakan[t]||0), 0);
  return { wp: hasTunggak.length, total };
}

export function getStatsByRW() {
  const map = {};
  wpData.forEach(d => {
    const rw = d.rw === "luar" ? "luar" : d.rw;
    if (!map[rw]) map[rw] = { wp:0, total:0 };
    map[rw].wp++;
    map[rw].total += d.total;
  });
  return map;
}

export function getStatsByRT(rw) {
  const map = {};
  const subset = rw ? wpData.filter(d => d.rw===rw) : wpData;
  subset.forEach(d => {
    const rt = d.rt === "luar" ? "luar" : d.rt;
    if (!map[rt]) map[rt] = { wp:0, total:0 };
    map[rt].wp++;
    map[rt].total += d.total;
  });
  return map;
}

export function getTunggakanPerTahun() {
  const map = {};
  TAHUN_LIST.forEach(y => { map[y] = { wp:0, total:0 }; });
  wpData.forEach(d => {
    Object.entries(d.tunggakan).forEach(([t,v]) => {
      if (map[t]) { map[t].wp++; map[t].total += v; }
    });
  });
  return map;
}

export function getSubset(dusun=0) {
  if (dusun === 0) return wpData;
  if (dusun === "luar") return wpData.filter(d => d.rw==="luar");
  return wpData.filter(d => getDusun(d.rw)===dusun);
}

export function searchWP(query="", filterRW="", filterTahun="", limit=100) {
  const q = query.toLowerCase();
  return wpData.filter(d => {
    if (q && !d.nama.toLowerCase().includes(q) && !d.nop.includes(q)) return false;
    if (filterRW && d.rw !== filterRW) return false;
    if (filterTahun && !d.tunggakan[filterTahun]) return false;
    return true;
  }).slice(0, limit);
}

// ─── PAYMENT ─────────────────────────────────────────────────
export function processApproval(id, approved, approvedBy) {
  const p = pendingList.find(x => x.id===id);
  if (!p || p.status!=="pending") return null;
  p.status   = approved ? "lunas" : "rejected";
  p.ketAdmin = approved ? `Disetujui oleh ${approvedBy}` : `Ditolak oleh ${approvedBy}`;
  if (approved && p.wpRef) {
    // Hapus dari tunggakan (mark lunas)
    delete p.wpRef.tunggakan[p.tahun];
    p.wpRef.total = Object.values(p.wpRef.tunggakan).reduce((s,v)=>s+v,0);
    riwayatList.unshift({ id:riwayatList.length+1, nop:p.nop, nama:p.nama, tahun:p.tahun, petugas:p.petugas, tglLunas:new Date().toLocaleDateString("id-ID"), approvedBy });
  }
  return p;
}

export function submitPayment({ wpId, tahun, petugasNama, file }) {
  const wp = wpData.find(w => w.id===wpId);
  if (!wp) return null;
  const item = {
    id: pendingList.length+1, nop:wp.nop, nama:wp.nama, tahun,
    petugas:petugasNama, tanggal:new Date().toLocaleDateString("id-ID"),
    status:"pending", buktiUrl:file?URL.createObjectURL(file):null,
    ketAdmin:"", wpRef:wp,
  };
  pendingList.unshift(item);
  return item;
}

export function addWP(data) {
  const newWP = { id:wpData.length+1, wp:0, tunggakan:{}, total:0, ...data };
  wpData.push(newWP);
  return newWP;
}

export function addPetugas({ nama, username, password, role, wilayah }) {
  const p = { id:petugasList.length+1, nama, username, password, role, wilayah, totalUpload:0 };
  petugasList.push(p);
  users.push({ username, password, role, nama, wilayah });
  return p;
}

export function getPendingApprovals() {
  return pendingList.filter(p => p.status==="pending");
}

export function getRWList() {
  const set = new Set(wpData.map(d => d.rw));
  return [...set].sort((a,b) => {
    if (a==="luar") return 1;
    if (b==="luar") return -1;
    return +a - +b;
  });
}

